"use strict";(self.webpackChunkheiman_wiki_public=self.webpackChunkheiman_wiki_public||[]).push([["3643"],{4458(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/heiman-wiki-public/pt/blog/welcome","source":"@site/i18n/pt/docusaurus-plugin-content-blog/2021-08-26-welcome/index.mdx","title":"Bem-vindo \xe0 Wiki da Heiman Technology","description":"Bem-vindo \xe0 Wiki da Heiman Technology! Esta \xe9 a base de conhecimento oficial, reunindo documenta\xe7\xe3o de produtos, solu\xe7\xf5es t\xe9cnicas, not\xedcias do setor e atualiza\xe7\xf5es da empresa.","date":"2021-08-26T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/pt/blog/tags/heiman","description":"Not\xedcias e atualiza\xe7\xf5es da Heiman Technology"}],"readingTime":0.74,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/pt/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"welcome","title":"Bem-vindo \xe0 Wiki da Heiman Technology","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"nextItem":{"title":"Detector de Fuma\xe7a Inteligente Heiman Matter Lan\xe7ado Oficialmente","permalink":"/heiman-wiki-public/pt/blog/mdx-blog-post"}},"content":"Bem-vindo \xe0 Wiki da Heiman Technology! Esta \xe9 a base de conhecimento oficial, reunindo documenta\xe7\xe3o de produtos, solu\xe7\xf5es t\xe9cnicas, not\xedcias do setor e atualiza\xe7\xf5es da empresa.\\n\\n{/* truncate */}\\n\\n## Sobre Este Site\\n\\nA Wiki da Heiman Technology \xe9 dedicada a fornecer um recurso t\xe9cnico completo para parceiros, desenvolvedores e clientes:\\n\\n- **Produtos** \u2014 Seguran\xe7a contra Inc\xeandios Inteligente, Seguran\xe7a de G\xe1s Inteligente, Cuidado de Idosos Inteligente, Sensores Inteligentes\\n- **Solu\xe7\xf5es** \u2014 Solu\xe7\xf5es de seguran\xe7a inteligente em n\xedvel industrial\\n- **Documenta\xe7\xe3o T\xe9cnica** \u2014 Guias de integra\xe7\xe3o de API, uso de SDK, manuais de instala\xe7\xe3o\\n- **Insights do Setor** \u2014 Tend\xeancias de seguran\xe7a inteligente e interpreta\xe7\xe3o de pol\xedticas\\n\\n## Navega\xe7\xe3o R\xe1pida\\n\\n- Navegue por [Produtos e Solu\xe7\xf5es](/docs/tutorial-basics/create-a-page)\\n- Leia [Sobre N\xf3s](/docs/intro) para conhecer a hist\xf3ria da Heiman\\n- Visite o [Site Oficial da Heiman](https://www.heiman.com.cn)\\n\\nPara qualquer d\xfavida, ligue para nossa linha direta **400-8959-500** ou entre em contato com o suporte online."},{"id":"mdx-blog-post","metadata":{"permalink":"/heiman-wiki-public/pt/blog/mdx-blog-post","source":"@site/i18n/pt/docusaurus-plugin-content-blog/2021-08-01-mdx-blog-post.mdx","title":"Detector de Fuma\xe7a Inteligente Heiman Matter Lan\xe7ado Oficialmente","description":"O detector de fuma\xe7a inteligente de nova gera\xe7\xe3o da Heiman Technology com protocolo Matter, o HS1SA-M, foi oficialmente lan\xe7ado \u2014 um dos primeiros detectores de fuma\xe7a do setor a receber a certifica\xe7\xe3o Matter 1.2.","date":"2021-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Matter","permalink":"/heiman-wiki-public/pt/blog/tags/matter","description":"Conte\xfado relacionado ao protocolo Matter"},{"inline":false,"label":"Seguran\xe7a contra Inc\xeandios Inteligente","permalink":"/heiman-wiki-public/pt/blog/tags/smart-fire","description":"Produtos e solu\xe7\xf5es de seguran\xe7a contra inc\xeandios inteligente"}],"readingTime":0.75,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/pt/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"mdx-blog-post","title":"Detector de Fuma\xe7a Inteligente Heiman Matter Lan\xe7ado Oficialmente","authors":["heiman"],"tags":["matter","smart-fire"]},"unlisted":false,"prevItem":{"title":"Bem-vindo \xe0 Wiki da Heiman Technology","permalink":"/heiman-wiki-public/pt/blog/welcome"},"nextItem":{"title":"Marcos da Heiman Technology","permalink":"/heiman-wiki-public/pt/blog/long-blog-post"}},"content":"O detector de fuma\xe7a inteligente de nova gera\xe7\xe3o da Heiman Technology com protocolo Matter, o HS1SA-M, foi oficialmente lan\xe7ado \u2014 um dos primeiros detectores de fuma\xe7a do setor a receber a certifica\xe7\xe3o Matter 1.2.\\n\\n{/* truncate */}\\n\\n:::tip\\n\\nO HS1SA-M suporta Apple HomeKit, Amazon Alexa, Google Home e Samsung SmartThings \u2014 os quatro principais ecossistemas de casa inteligente.\\n\\n:::\\n\\n## Principais Caracter\xedsticas\\n\\n- **Certificado Matter 1.2** \u2014 Interoperabilidade entre marcas e ecossistemas\\n- **Sensor de Fuma\xe7a Fotoel\xe9trico** \u2014 Resposta r\xe1pida a v\xe1rios tipos de fuma\xe7a de inc\xeandio\\n- **Alarme por Voz** \u2014 M\xfaltiplas op\xe7\xf5es de idioma, alertas claros de perigo\\n- **Fun\xe7\xe3o de Autoteste** \u2014 Autoverifica\xe7\xf5es regulares para garantir opera\xe7\xe3o normal\\n- **Notifica\xe7\xe3o Remota** \u2014 Alertas push em tempo real para o APP do seu celular\\n\\n## Compatibilidade\\n\\nO HS1SA-M integra-se perfeitamente \xe0s principais plataformas de casa inteligente sem necessidade de gateway adicional \u2014 gerencie tudo diretamente do seu celular.\\n\\nVisite a p\xe1gina de [Produtos](/docs/tutorial-basics/create-a-page) para saber mais."},{"id":"long-blog-post","metadata":{"permalink":"/heiman-wiki-public/pt/blog/long-blog-post","source":"@site/i18n/pt/docusaurus-plugin-content-blog/2019-05-29-long-blog-post.mdx","title":"Marcos da Heiman Technology","description":"Desde sua funda\xe7\xe3o em 2005, a Heiman Technology percorreu mais de 20 anos. Este artigo revisa os principais marcos da Heiman.","date":"2019-05-29T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/pt/blog/tags/heiman","description":"Not\xedcias e atualiza\xe7\xf5es da Heiman Technology"}],"readingTime":1.27,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/pt/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"long-blog-post","title":"Marcos da Heiman Technology","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Detector de Fuma\xe7a Inteligente Heiman Matter Lan\xe7ado Oficialmente","permalink":"/heiman-wiki-public/pt/blog/mdx-blog-post"},"nextItem":{"title":"Heiman Technology Reconhecida como Empresa Nacional \\"Pequeno Gigante\\"","permalink":"/heiman-wiki-public/pt/blog/first-blog-post"}},"content":"Desde sua funda\xe7\xe3o em 2005, a Heiman Technology percorreu mais de 20 anos. Este artigo revisa os principais marcos da Heiman.\\n\\n{/* truncate */}\\n\\n## 2005 - Funda\xe7\xe3o da Empresa\\n\\nA Shenzhen Heiman Technology Co., Ltd. foi oficialmente estabelecida, entrando no campo de sensores de seguran\xe7a.\\n\\n## 2006 - In\xedcio Internacional\\n\\nM\xfaltiplos produtos obtiveram a certifica\xe7\xe3o CE da UE e firmaram parceria com a China Mobile.\\n\\n## 2011 - Avan\xe7o em Certifica\xe7\xe3o Internacional\\n\\nM\xfaltiplos produtos obtiveram as certifica\xe7\xf5es EU EN54-7 e EN14604, atingindo padr\xf5es internacionais de qualidade.\\n\\n## 2012 - Transforma\xe7\xe3o para Casa Inteligente\\n\\nO projeto de casa inteligente foi totalmente lan\xe7ado, transformando a Heiman em uma empresa especializada em P&D, produ\xe7\xe3o e vendas de produtos para casa inteligente.\\n\\n## 2017 - Grandes Avan\xe7os\\n\\n- Desenvolveu o primeiro alarme de fuma\xe7a NB-IoT da China\\n- Ganhou 2 Pr\xeamios Red Dot Design\\n- Obteve certifica\xe7\xe3o MFi, qualificando-se como fabricante Apple\\n\\n## 2020 - Impulso de Capital\\n\\nConcluiu financiamento S\xe9rie A com o Shenzhen High-tech Investment Group, reconhecida como \\"PME Especializada e Nova da Prov\xedncia de Guangdong\\".\\n\\n## 2022 - Reconhecimento Nacional\\n\\nReconhecida como Empresa Nacional Especializada e Nova \\"Pequeno Gigante\\". A s\xe9rie K1 ganhou o Pr\xeamio Red Dot Design.\\n\\n## 2023 - Lideran\xe7a em Padr\xf5es Internacionais\\n\\nO laborat\xf3rio de testes da Heiman obteve oficialmente a certifica\xe7\xe3o CNAS. Alarmes de fuma\xe7a e CO foram dos primeiros a obter certifica\xe7\xe3o Matter 1.2.\\n\\n## 2024 - Presente\\n\\nContinuando a inova\xe7\xe3o, aprofundando o compromisso com Seguran\xe7a contra Inc\xeandios Inteligente, Seguran\xe7a de G\xe1s Inteligente, Cuidado de Idosos Inteligente e Sensores Inteligentes, fornecendo produtos e servi\xe7os de qualidade para clientes em mais de 100 pa\xedses em todo o mundo."},{"id":"first-blog-post","metadata":{"permalink":"/heiman-wiki-public/pt/blog/first-blog-post","source":"@site/i18n/pt/docusaurus-plugin-content-blog/2019-05-28-first-blog-post.mdx","title":"Heiman Technology Reconhecida como Empresa Nacional \\"Pequeno Gigante\\"","description":"Em 2022, a Heiman Technology foi oficialmente reconhecida como uma Empresa Nacional Especializada e Nova \\"Pequeno Gigante\\" por sua profunda acumula\xe7\xe3o t\xe9cnica e inova\xe7\xe3o no campo de sensores inteligentes.","date":"2019-05-28T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/pt/blog/tags/heiman","description":"Not\xedcias e atualiza\xe7\xf5es da Heiman Technology"}],"readingTime":0.5,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/pt/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"first-blog-post","title":"Heiman Technology Reconhecida como Empresa Nacional \\"Pequeno Gigante\\"","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Marcos da Heiman Technology","permalink":"/heiman-wiki-public/pt/blog/long-blog-post"}},"content":"Em 2022, a Heiman Technology foi oficialmente reconhecida como uma Empresa Nacional Especializada e Nova \\"Pequeno Gigante\\" por sua profunda acumula\xe7\xe3o t\xe9cnica e inova\xe7\xe3o no campo de sensores inteligentes.\\n\\n{/* truncate */}\\n\\nEste reconhecimento nacional afirma a excel\xeancia da Heiman em especializa\xe7\xe3o, refinamento, diferencia\xe7\xe3o e inova\xe7\xe3o. A Heiman continuar\xe1 a aprofundar seus esfor\xe7os em Seguran\xe7a contra Inc\xeandios Inteligente, Seguran\xe7a de G\xe1s Inteligente, Cuidado de Idosos Inteligente e Sensores Inteligentes, fornecendo consistentemente produtos e servi\xe7os de alta qualidade aos clientes.\\n\\nA Heiman havia recebido anteriormente o reconhecimento como Empresa Nacional de Alta Tecnologia e como PME Especializada e Nova da Prov\xedncia de Guangdong."}]}}')}}]);